import { useState, useEffect, useRef } from 'react';
import { Box, Typography, Grid, Card, CardContent, Chip, CircularProgress, Alert, Stack, FormControl, InputLabel, Select, MenuItem, TextField, InputAdornment, useTheme } from '@mui/material';
import { motion, useInView } from 'framer-motion';
import type { Article } from '../types/Article';
import ImageWithFallback from './ImageWithFallback';
import { getCurrentSeason } from '../lib/seasonalEngine';
import { getSeasonWatermark } from './SeasonalEffects';
import SearchIcon from '@mui/icons-material/Search';
import SentimentDissatisfiedIcon from '@mui/icons-material/SentimentDissatisfied';

const AnimatedCounter = ({ value, label }: { value: number, label: string }) => {
  const [count, setCount] = useState(0);
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true, margin: "0px" });

  useEffect(() => {
    if (isInView) {
      let start = 0;
      const end = value;
      if (start === end) return;
      const duration = 1500;
      let startTimestamp: number | null = null;
      const step = (timestamp: number) => {
        if (!startTimestamp) startTimestamp = timestamp;
        const progress = Math.min((timestamp - startTimestamp) / duration, 1);
        setCount(Math.floor(progress * (end - start) + start));
        if (progress < 1) {
          window.requestAnimationFrame(step);
        }
      };
      window.requestAnimationFrame(step);
    }
  }, [value, isInView]);

  return (
    <Box ref={ref} sx={{ textAlign: 'center', p: { xs: 1.5, sm: 2 }, flex: 1 }}>
      <Typography variant="h3" sx={{ fontWeight: 900, color: 'primary.main', mb: 0.5, fontSize: { xs: '1.75rem', sm: '3rem' } }}>
        {count}+
      </Typography>
      <Typography variant="body2" color="text.secondary" sx={{ fontWeight: 700, textTransform: 'uppercase', letterSpacing: { xs: 0, sm: 1 }, fontSize: { xs: '0.65rem', sm: '0.875rem' } }}>
        {label}
      </Typography>
    </Box>
  );
};

export default function ArticlesGallery() {
  const [articles, setArticles] = useState<Article[]>([]);
  const [articleTypes, setArticleTypes] = useState<any[]>([]);
  const [articleMajors, setArticleMajors] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const muiTheme = useTheme();
  const season = getCurrentSeason();
  const watermarkUrl = season.id !== 'NONE' ? getSeasonWatermark(season.id) : null;

  const [search, setSearch] = useState('');
  const [currentType, setCurrentType] = useState('All');
  const [currentMajor, setCurrentMajor] = useState('All');

  const [isFiltering, setIsFiltering] = useState(false);
  const [visibleCount, setVisibleCount] = useState(9);

  const observer = useRef<IntersectionObserver | null>(null);
  const lastElementRef = (node: HTMLDivElement | null) => {
    if (loading || isFiltering) return;
    if (observer.current) observer.current.disconnect();
    observer.current = new IntersectionObserver(entries => {
      if (entries[0].isIntersecting) {
        setVisibleCount(prev => prev + 9);
      }
    }, { threshold: 0.1 });
    if (node) observer.current.observe(node);
  };

  useEffect(() => {
    setVisibleCount(9);
    setIsFiltering(true);
    const timer = setTimeout(() => setIsFiltering(false), 500);
    return () => clearTimeout(timer);
  }, [search, currentType, currentMajor]);

  useEffect(() => {
    const localArticlesUrl = `${import.meta.env.BASE_URL}data/articles.json`;
    const localTypesUrl = `${import.meta.env.BASE_URL}data/articleTypes.json`;
    const localMajorsUrl = `${import.meta.env.BASE_URL}data/majors.json`;

    const fetchWithFallback = async (apiUrl: string, localUrl: string) => {
      try {
        const res = await fetch(apiUrl);
        if (!res.ok) throw new Error('API limit reached or error');
        const json = await res.json();
        const decoded = decodeURIComponent(escape(atob(json.content)));
        return JSON.parse(decoded);
      } catch (err) {
        const localRes = await fetch(localUrl);
        if (!localRes.ok) return [];
        return localRes.json();
      }
    };

    let pPromise = fetch(localArticlesUrl).then(res => res.json());
    let tPromise = fetch(localTypesUrl).then(res => res.json()).catch(() => []);
    let mPromise = fetch(localMajorsUrl).then(res => res.json()).catch(() => []);

    if (window.location.hostname.includes('.github.io')) {
      const owner = window.location.hostname.split('.')[0];
      const repo = window.location.pathname.split('/')[1];
      if (owner && repo) {
        pPromise = fetchWithFallback(`https://api.github.com/repos/${owner}/${repo}/contents/public/data/articles.json`, localArticlesUrl);
        tPromise = fetchWithFallback(`https://api.github.com/repos/${owner}/${repo}/contents/public/data/articleTypes.json`, localTypesUrl);
        mPromise = fetchWithFallback(`https://api.github.com/repos/${owner}/${repo}/contents/public/data/majors.json`, localMajorsUrl);
      }
    }

    Promise.all([pPromise, tPromise, mPromise])
      .then(([artData, typesData, majorsData]) => {
        const resolvedArticles = (artData || []).map((a: any) => {
          const tObj = (typesData || []).find((t: any) => t.id === a.type);
          const mObj = (majorsData || []).find((m: any) => m.id === a.major);
          return {
            ...a,
            type: tObj?.name || a.type,
            typeBg: tObj?.bg || '#E0E7FF',
            typeText: tObj?.text || '#3730A3',
            major: mObj?.name || a.major,
            majorBg: mObj?.bg || 'transparent',
            majorText: mObj?.text || '#4B5563',
          };
        });
        setArticles(resolvedArticles);
        setArticleTypes(typesData || []);
        setArticleMajors(majorsData || []);
        setLoading(false);
      })
      .catch((err: any) => {
        console.error('Error fetching articles:', err);
        setError('Không thể tải danh sách bài viết.');
        setLoading(false);
      });
  }, []);

  if (loading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', p: 8 }}>
        <CircularProgress />
      </Box>
    );
  }

  if (error) {
    return (
      <Box sx={{ p: 4 }}>
        <Alert severity="error">{error}</Alert>
      </Box>
    );
  }

  const types = ['All', ...Array.from(new Set([...articleTypes.map(t => t.name), ...articles.map(a => a.type).filter(Boolean)]))];
  const majors = ['All', ...Array.from(new Set([...articleMajors.map(m => m.name), ...articles.map(a => a.major).filter(Boolean)]))];

  const getTypeCount = (type: string) => type === 'All' ? articles.length : articles.filter(a => a.type === type).length;
  const getMajorCount = (major: string) => major === 'All' ? articles.length : articles.filter(a => a.major === major).length;

  const filteredArticles = articles.filter(a => {
    const matchesSearch = a.title.toLowerCase().includes(search.toLowerCase());
    const matchesType = currentType === 'All' || a.type === currentType;
    const matchesMajor = currentMajor === 'All' || a.major === currentMajor;
    return matchesSearch && matchesType && matchesMajor;
  });

  const displayedArticles = filteredArticles.slice(0, visibleCount);

  return (
    <Box>
      {/* Hero */}
      <motion.div initial={{ opacity: 0, y: -16 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.5 }}>
        <Box sx={{ mb: 5, textAlign: 'center', mt: 2 }}>
          <Typography variant="h3" component="h1" sx={{ mb: 1.5, fontWeight: 800, color: 'text.primary', fontSize: { xs: '2.25rem', sm: '3rem' } }}>
            Tin tức & <span style={{ color: muiTheme.palette.primary.main }}>Bài viết</span>
          </Typography>
          <Typography variant="body1" color="text.secondary" sx={{ maxWidth: 560, mx: 'auto', lineHeight: 1.7, mb: 4 }}>
            Các bài viết, tin tức và các hoạt động nổi bật của sinh viên
          </Typography>

          <Box sx={{ display: 'flex', justifyContent: 'center', maxWidth: 600, mx: 'auto', bgcolor: 'background.paper', borderRadius: 4, boxShadow: '0 10px 40px -10px rgba(0,0,0,0.08)', border: '1px solid', borderColor: 'divider', overflow: 'hidden' }}>
            <AnimatedCounter value={articles.length} label="Bài viết" />
            <Box sx={{ width: '1px', bgcolor: 'divider' }} />
            <AnimatedCounter value={articleTypes.length} label="Chủ đề" />
            <Box sx={{ width: '1px', bgcolor: 'divider' }} />
            <AnimatedCounter value={articleMajors.length} label="Chuyên ngành" />
          </Box>
        </Box>
      </motion.div>

      {/* Filter Bar */}
      <motion.div initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.4 }}>
        <Box sx={{
          background: muiTheme.palette.mode === 'light' ? 'rgba(255, 255, 255, 0.7)' : 'rgba(30, 41, 59, 0.7)',
          backdropFilter: 'blur(24px)',
          border: '1px solid', borderColor: 'divider', borderRadius: 4, 
          boxShadow: '0 8px 32px rgba(0,0,0,0.04)',
          p: { xs: 2.5, sm: 3.5 }, mb: 5,
        }}>
          {/* Types Row */}
          <Box sx={{ mb: 3 }}>
            <Stack direction="row" spacing={1} sx={{ overflowX: 'auto', pb: 1, '&::-webkit-scrollbar': { display: 'none' }, msOverflowStyle: 'none', scrollbarWidth: 'none' }}>
              {types.map(cat => (
                <Chip
                  key={cat}
                  label={`${cat === 'All' ? 'Tất cả loại bài' : cat} (${getTypeCount(cat)})`}
                  onClick={() => setCurrentType(cat)}
                  variant={currentType === cat ? 'filled' : 'outlined'}
                  sx={{
                    fontWeight: 600, fontSize: '0.85rem', cursor: 'pointer', height: 32, px: 0.5, flexShrink: 0,
                    ...(currentType === cat
                      ? {
                        background: 'linear-gradient(135deg, #2563EB, #1D4ED8)',
                        color: '#FFF', border: 'none', boxShadow: '0 4px 12px rgba(37, 99, 235, 0.3)',
                      }
                      : {
                        borderColor: 'divider', color: 'text.secondary',
                        '&:hover': { borderColor: 'primary.main', color: 'primary.main', bgcolor: 'action.hover' },
                      }),
                  }}
                />
              ))}
            </Stack>
          </Box>

          {/* Filters & Search Row */}
          <Grid container spacing={2}>
            <Grid size={{ xs: 12, sm: 6, md: 4 }}>
              <FormControl size="small" fullWidth>
                <InputLabel>Chuyên ngành</InputLabel>
                <Select
                  value={currentMajor}
                  label="Chuyên ngành"
                  onChange={e => setCurrentMajor(e.target.value)}
                  sx={{ 
                    borderRadius: 3, 
                    bgcolor: muiTheme.palette.mode === 'light' ? 'rgba(255, 255, 255, 0.5)' : 'rgba(15, 23, 42, 0.5)',
                    '&:hover': { bgcolor: 'background.paper' },
                    transition: 'all 0.3s'
                  }}
                >
                  {majors.map(major => (
                    <MenuItem key={major} value={major}>{(major === 'All' ? 'Tất cả chuyên ngành' : major)} ({getMajorCount(major)})</MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Grid>

            <Grid size={{ xs: 12, sm: 6, md: 8 }}>
              <TextField
                fullWidth
                size="small"
                placeholder="Tìm kiếm bài viết..."
                value={search}
                onChange={e => setSearch(e.target.value)}
                sx={{
                  '& .MuiOutlinedInput-root': { 
                    borderRadius: 3, 
                    bgcolor: muiTheme.palette.mode === 'light' ? 'rgba(255, 255, 255, 0.5)' : 'rgba(15, 23, 42, 0.5)',
                    '&:hover': { bgcolor: 'background.paper' },
                    transition: 'all 0.3s'
                  },
                }}
                slotProps={{
                  input: {
                    startAdornment: (
                      <InputAdornment position="start">
                        <SearchIcon sx={{ color: 'text.secondary', fontSize: 20 }} />
                      </InputAdornment>
                    ),
                    sx: { borderRadius: 2, bgcolor: 'background.default' }
                  }
                }}
              />
            </Grid>
          </Grid>
        </Box>
      </motion.div>

      <Box sx={{ display: 'flex', justifyContent: 'flex-start', mb: 3, px: 1 }}>
        <Typography variant="body2" color="text.secondary" sx={{ fontWeight: 600 }}>
          Hiển thị {filteredArticles.length} bài viết
        </Typography>
      </Box>

      {/* Grid */}
      {isFiltering ? (
        <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', py: 10, gap: 2 }}>
          <CircularProgress size={40} thickness={4} sx={{ color: 'primary.main' }} />
          <Typography color="text.secondary">Đang tải dữ liệu...</Typography>
        </Box>
      ) : filteredArticles.length === 0 ? (
        <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }}>
          <Box sx={{ textAlign: 'center', py: 10, px: 3, bgcolor: 'background.paper', borderRadius: 4, border: '1px solid', borderColor: 'divider' }}>
            <SentimentDissatisfiedIcon sx={{ fontSize: 56, color: 'text.disabled', mb: 2 }} />
            <Typography variant="h6" color="text.secondary" sx={{ fontWeight: 600 }}>
              Không tìm thấy bài viết nào
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 1 }}>
              Hãy thử tìm kiếm với từ khoá hoặc phân loại khác.
            </Typography>
          </Box>
        </motion.div>
      ) : (
        <>
          <Grid container spacing={4}>
            {displayedArticles.map((article, index) => (
              <Grid size={{ xs: 12, sm: 6, md: 4 }} key={article.id}>
                <motion.div
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ duration: 0.4, delay: index * 0.1 }}
                  whileHover={{ y: -8 }}
                >
                  <Card
                    sx={{
                      borderRadius: 4,
                      overflow: 'hidden',
                      boxShadow: '0 10px 30px rgba(0,0,0,0.08)',
                      height: '100%',
                      display: 'flex',
                      flexDirection: 'column',
                      cursor: 'pointer',
                      textDecoration: 'none',
                      bgcolor: 'background.paper',
                    }}
                    component="a"
                    href={article.link}
                    target="_blank"
                    rel="noopener noreferrer"
                  >
                    <ImageWithFallback
                      src={article.imageUrl}
                      alt={article.title}
                      fallbackText={article.type}
                      iconKeyword={article.major}
                      height={200}
                    />
                    <CardContent sx={{ flexGrow: 1, p: 3, position: 'relative' }}>
                      {watermarkUrl && (
                        <Box
                          sx={{
                            position: 'absolute',
                            top: '50%',
                            right: -30,
                            width: 200,
                            height: 200,
                            backgroundImage: watermarkUrl,
                            backgroundSize: 'contain',
                            backgroundRepeat: 'no-repeat',
                            backgroundPosition: 'center right',
                            opacity: muiTheme.palette.mode === 'dark' ? 0.20 : 0.12,
                            pointerEvents: 'none',
                            zIndex: 0,
                            transform: 'translateY(-50%) rotate(-15deg)',
                            WebkitMaskImage: 'radial-gradient(circle at center right, black 30%, transparent 90%)',
                            maskImage: 'radial-gradient(circle at center right, black 30%, transparent 90%)',
                          }}
                        />
                      )}
                      <Box sx={{ position: 'relative', zIndex: 1 }}>
                        <Box sx={{ display: 'flex', gap: 1, mb: 2 }}>
                          {article.type && (
                            <Chip label={article.type} size="small" sx={{ fontWeight: 700, bgcolor: article.typeBg, color: article.typeText }} />
                          )}
                          {article.major && (
                            <Chip label={article.major} size="small" variant="outlined" sx={{ fontWeight: 700, borderColor: article.majorText !== '#4B5563' ? article.majorText : 'divider', color: article.majorText }} />
                          )}
                          {article.year && (
                            <Chip label={article.year} size="small" variant="outlined" sx={{ fontWeight: 700, borderColor: 'divider', color: 'text.secondary' }} />
                          )}
                        </Box>
                        <Typography variant="h6" sx={{ fontWeight: 700, lineHeight: 1.4, color: 'text.primary', display: '-webkit-box', WebkitLineClamp: 3, WebkitBoxOrient: 'vertical', overflow: 'hidden' }}>
                          {article.title}
                        </Typography>
                      </Box>
                    </CardContent>
                  </Card>
                </motion.div>
              </Grid>
            ))}
          </Grid>
          {visibleCount < filteredArticles.length && (
            <Box ref={lastElementRef} sx={{ textAlign: 'center', mt: 5, py: 2 }}>
              <CircularProgress size={32} sx={{ color: 'primary.main' }} />
            </Box>
          )}
        </>
      )}
    </Box>
  );
}

import { useState } from 'react';
import { Box, Typography } from '@mui/material';
import { getCurrentSeason } from '../lib/seasonalEngine';
import { getSeasonWatermark } from './SeasonalEffects';

const MAJOR_ASSETS_3D = {
  WEB: `url("https://raw.githubusercontent.com/microsoft/fluentui-emoji/main/assets/Globe%20with%20meridians/3D/globe_with_meridians_3d.png")`,
  GAME: `url("https://raw.githubusercontent.com/microsoft/fluentui-emoji/main/assets/Video%20game/3D/video_game_3d.png")`,
  AI: `url("https://raw.githubusercontent.com/microsoft/fluentui-emoji/main/assets/Brain/3D/brain_3d.png")`,
  MOBILE: `url("https://raw.githubusercontent.com/microsoft/fluentui-emoji/main/assets/Mobile%20phone/3D/mobile_phone_3d.png")`,
  DEFAULT: `url("https://raw.githubusercontent.com/microsoft/fluentui-emoji/main/assets/File%20folder/3D/file_folder_3d.png")`,
};

const MASCULINE_GRADIENTS = [
  'linear-gradient(135deg, #60A5FA 0%, #1D4ED8 100%)', // Bright Blue to Deep Blue
  'linear-gradient(135deg, #38BDF8 0%, #0369A1 100%)', // Sky Blue to Ocean
  'linear-gradient(135deg, #2DD4BF 0%, #0F766E 100%)', // Bright Teal to Deep Teal
  'linear-gradient(135deg, #FB923C 0%, #C2410C 100%)', // Energetic Orange
  'linear-gradient(135deg, #34D399 0%, #047857 100%)', // Emerald Green
  'linear-gradient(135deg, #94A3B8 0%, #334155 100%)', // Tech Slate Gray
  'linear-gradient(135deg, #818CF8 0%, #3730A3 100%)', // Indigo
  'linear-gradient(135deg, #F87171 0%, #B91C1C 100%)', // Sporty Red
  'linear-gradient(135deg, #22D3EE 0%, #0E7490 100%)', // Cyan
  'linear-gradient(135deg, #A3E635 0%, #4D7C0F 100%)', // Lime Green
];

export const getFallbackConfig = (text: string = '') => {
  const m = text.toLowerCase();

  let fallback3dUrl = MAJOR_ASSETS_3D.DEFAULT;
  if (m.includes('web') || m.includes('website')) fallback3dUrl = MAJOR_ASSETS_3D.WEB;
  else if (m.includes('game') || m.includes('trò chơi')) fallback3dUrl = MAJOR_ASSETS_3D.GAME;
  else if (m.includes('ai') || m.includes('trí tuệ') || m.includes('data')) fallback3dUrl = MAJOR_ASSETS_3D.AI;
  else if (m.includes('mobile') || m.includes('app') || m.includes('di động') || m.includes('ứng dụng')) fallback3dUrl = MAJOR_ASSETS_3D.MOBILE;

  // Hash string to pick a gradient index
  let hash = 0;
  for (let i = 0; i < text.length; i++) {
    hash = text.charCodeAt(i) + ((hash << 5) - hash);
  }

  const gradientIndex = Math.abs(hash) % MASCULINE_GRADIENTS.length;
  const gradient = MASCULINE_GRADIENTS[gradientIndex];

  return { fallback3dUrl, gradient };
};

export default function ImageWithFallback({ src, alt, fallbackText, iconKeyword, height = 200, className, sx = {} }: { src: string, alt: string, fallbackText?: string, iconKeyword?: string, height?: number | string, className?: string, sx?: any }) {
  const [error, setError] = useState(false);
  const season = getCurrentSeason();
  const seasonWatermarkUrl = season.id !== 'NONE' ? getSeasonWatermark(season.id) : null;

  if (!src || error) {
    const { fallback3dUrl, gradient } = getFallbackConfig(iconKeyword || fallbackText || alt);
    const finalIconUrl = seasonWatermarkUrl || fallback3dUrl;

    return (
      <Box 
        className={className}
        sx={{ 
          height, 
          display: 'flex', 
          flexDirection: 'column',
          alignItems: 'center', 
          justifyContent: 'center', 
          background: gradient, 
          color: 'white',
          position: 'relative',
          overflow: 'hidden',
          ...sx
        }}
      >
        {/* Subtle geometric pattern */}
        <Box sx={{ position: 'absolute', top: -50, left: -50, width: 150, height: 150, borderRadius: '50%', background: 'rgba(255,255,255,0.05)', filter: 'blur(20px)' }} />
        <Box sx={{ position: 'absolute', bottom: -30, right: -30, width: 100, height: 100, borderRadius: '50%', background: 'rgba(255,255,255,0.08)', filter: 'blur(15px)' }} />
        <Box sx={{ position: 'absolute', top: '20%', right: '10%', width: 60, height: 60, borderRadius: '20%', background: 'rgba(255,255,255,0.03)', transform: 'rotate(45deg)' }} />

        <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 1.5, zIndex: 1, p: 2 }}>
          <Box sx={{ p: 1.5, borderRadius: '20%', background: 'rgba(255, 255, 255, 0.1)', backdropFilter: 'blur(10px)', border: '1px solid rgba(255,255,255,0.2)', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 8px 32px 0 rgba(0, 0, 0, 0.15)' }}>
            <Box sx={{ 
              width: 48, 
              height: 48, 
              backgroundImage: finalIconUrl,
              backgroundSize: 'contain',
              backgroundRepeat: 'no-repeat',
              backgroundPosition: 'center',
              filter: 'drop-shadow(0 4px 8px rgba(0,0,0,0.3))'
            }} />
          </Box>
          <Typography variant="subtitle2" sx={{ fontWeight: 900, fontSize: '0.9rem', letterSpacing: '0.5px', textTransform: 'uppercase', color: '#FFFFFF', textAlign: 'center', display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical', overflow: 'hidden', textShadow: '0px 2px 4px rgba(0,0,0,0.8), 0px 4px 12px rgba(0,0,0,0.6)' }}>
            {fallbackText || 'Dự án Sinh viên'}
          </Typography>
        </Box>
      </Box>
    );
  }

  return (
    <Box 
      component="img"
      className={className}
      src={src}
      alt={alt}
      onError={() => setError(true)}
      sx={{ 
        height, 
        width: '100%', 
        objectFit: 'cover',
        display: 'block',
        ...sx
      }}
    />
  );
}

